INSERT INTO CALENDAR_SHARE ( CAL_SHARE_CD, CAL_SHARE_NO, CAL_SHARE_ID, DEPT_CD, CAL_SHARE_NM, CAL_SHARE_DEPT_NM, CAL_SHARE_TYPE, CAL_SHARE_DATE ) SELECT SEQ_CAL_SHARE_CD.NEXTVAL, A.CAL_SHARE_NO, A.CAL_SHARE_ID, A.DEPT_CD, A.CAL_SHARE_NM, A.CAL_SHARE_DEPT_NM, A.CAL_SHARE_TYPE, SYSDATE FROM (
SELECT #{vo.calShareNo} AS CAL_SHARE_NO, #{vo.calShareId} AS CAL_SHARE_ID, #{vo.deptCd} AS DEPT_CD, #{vo.calShareNm} AS CAL_SHARE_NM, #{vo.calShareDeptNm} AS CAL_SHARE_DEPT_NM, #{vo.calShareType} AS CAL_SHARE_TYPE FROM DUAL
) A

