FILE_ID = #{fileId},
CAL_UPDATE = SYSDATE, CAL_IMPORTANT = #{calImportant}, CAL_LOCATION = #{calLocation}, CAL_BGNG_TM = TO_TIMESTAMP(#{calBgngTm}, 'YYYY/MM/DD HH24:MI:SS'), CAL_END_TM = TO_TIMESTAMP(#{calEndTm}, 'YYYY/MM/DD HH24:MI:SS'), CAL_SHARE = #{calShare}, CAL_ALLDAY = #{calAllday} WHERE CAL_NO = #{calNo}

